INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (1, 'Safety First: Our Commitment to You', 'safety-first-our-commitment-to-you', 'Discover the new safety features we have implemented to ensure every FlexyRide journey is secure.', '<p>At FlexyRide, your safety is our top priority. We have introduced enhanced driver background checks, real-time trip sharing, and an emergency SOS button directly in the app.</p><p>These features are designed to give you peace of mind whether you are riding across Accra or delivering a parcel.</p>', '', 'FlexyRide Safety Team', true, '2026-04-21 18:07:21.610977-07', '2026-04-21 18:07:21.635607-07', '2026-04-21 18:07:21.635627-07', 'https://images.unsplash.com/photo-1557333610-90ee4a951ecf?q=80&w=800', 'company');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (2, 'Expanding to Kumasi: The Garden City', 'expanding-to-kumasi-the-garden-city', 'We are thrilled to bring the FlexyRide revolution to the heart of the Ashanti region.', '<p>The wait is over! FlexyRide is now officially live in Kumasi. We are launching with over 500 verified drivers ready to provide safe, reliable, and affordable rides.</p><p>Download the app today and enter code KUMASI10 for a discount on your first 5 rides.</p>', '', 'Operations Desk', true, '2026-04-21 18:07:21.610982-07', '2026-04-21 18:07:21.638831-07', '2026-04-21 18:07:21.638842-07', 'https://images.unsplash.com/photo-1580674239581-4d48f7c7ef4e?q=80&w=800', 'company');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (3, 'The Future of Urban Delivery', 'the-future-of-urban-delivery', 'How Flexy Delivery is helping local businesses scale with efficient logistics.', '<p>Logistics shouldn''t be a bottleneck for growth. Flexy Delivery provides businesses of all sizes with a reliable fleet for last-mile delivery.</p><p>From documents to fragile parcels, our drivers handle every delivery with care and speed.</p>', '', 'Product Team', true, '2026-04-21 18:07:21.610983-07', '2026-04-21 18:07:21.641077-07', '2026-04-21 18:07:21.641087-07', 'https://images.unsplash.com/photo-1566576721346-d4a3b4eaad55?q=80&w=800', 'company');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (4, 'Safety First: Our Commitment to Every Rider', 'safety-first-our-commitment-to-every-rider', 'Discover the new safety features we have implemented to ensure every FlexyRide journey is as secure as possible.', '<h2>Your Safety is Non-Negotiable</h2><p>At FlexyRide, your safety is our top priority. We have introduced enhanced driver background checks, real-time trip sharing, and an emergency SOS button directly in the app.</p><p>These features are designed to give you peace of mind whether you are riding across Accra or delivering a parcel to a client.</p><h2>What We Have Built</h2><ul><li>Rigorous driver vetting with Ghana Police Service checks</li><li>Real-time trip sharing with family and friends</li><li>In-app SOS that alerts our 24/7 Incident Response Team</li><li>Automatic ride recording for dispute resolution</li></ul>', '', 'FlexyRide Safety Team', true, '2026-04-19 17:56:05.363655-07', '2026-04-24 17:56:05.369243-07', '2026-04-24 17:56:05.369251-07', 'https://images.unsplash.com/photo-1557333610-90ee4a951ecf?q=80&w=800', 'safety');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (5, 'FlexyRide Is Now Live in Kumasi', 'flexyride-is-now-live-in-kumasi', 'We are thrilled to bring the FlexyRide revolution to the heart of the Ashanti region — the Garden City.', '<h2>Kumasi, We Are Here!</h2><p>The wait is over. FlexyRide is now officially live in Kumasi with over 840 verified drivers ready to provide safe, reliable, and affordable rides.</p><p>Download the app today and enter code <strong>KUMASI10</strong> for a discount on your first 5 rides.</p><h2>What to Expect</h2><p>Riders in Kumasi will enjoy the same premium experience our Accra users love — transparent pricing, real-time tracking, and 24/7 support.</p>', '', 'Operations Desk', true, '2026-04-10 17:56:05.363655-07', '2026-04-24 17:56:05.372128-07', '2026-04-24 17:56:05.372136-07', 'https://images.unsplash.com/photo-1580674239581-4d48f7c7ef4e?q=80&w=800', 'company');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (6, 'How Flexy Delivery Powers Ghana Small Businesses', 'how-flexy-delivery-powers-ghana-small-businesses', 'How our last-mile delivery service is helping local businesses scale with fast, reliable logistics.', '<h2>Logistics Should Not Be a Bottleneck</h2><p>Flexy Delivery provides businesses of all sizes with a reliable fleet for last-mile delivery across Ghana''s major cities.</p><p>From documents to fragile parcels, our drivers handle every delivery with care and speed. Businesses get a real-time tracking link to share with their customers.</p><h2>Success Story</h2><p>"Since switching to Flexy Delivery, our on-time delivery rate jumped from 72% to 97%." — Abena O., Boutique Owner, Accra.</p>', '', 'Product Team', true, '2026-04-03 17:56:47.814215-07', '2026-04-24 17:56:47.829091-07', '2026-04-24 17:56:47.829118-07', 'https://images.unsplash.com/photo-1566576721346-d4a3b4eaad55?q=80&w=800', 'product');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (7, '5 Tips to Earn More as a FlexyRide Driver', '5-tips-to-earn-more-as-a-flexyride-driver', 'Our top-earning drivers share the habits and strategies that help them consistently maximise their weekly income.', '<h2>Work Smarter, Not Just Harder</h2><p>We analyzed data from our top 10% of drivers and found five habits they all share:</p><ol><li><strong>Peak Hours:</strong> Log on between 6–9am and 4–8pm for surge pricing.</li><li><strong>Airport Runs:</strong> Accra and Kumasi airport rides have higher base fares.</li><li><strong>Keep a High Rating:</strong> Drivers above 4.8★ get priority in the matching algorithm.</li><li><strong>Accept Quickly:</strong> Fast acceptance rates increase your daily ride count significantly.</li><li><strong>Stay Close to Hotspots:</strong> Use the driver heatmap in the app to position yourself near demand.</li></ol>', '', 'Driver Success Team', true, '2026-03-25 17:56:47.814215-07', '2026-04-24 17:56:47.839759-07', '2026-04-24 17:56:47.840816-07', 'https://images.unsplash.com/photo-1449965408869-eaa3f722e40d?q=80&w=800', 'driver');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (8, 'Exploring Ghana: The Best Weekend Trips from Accra', 'exploring-ghana-the-best-weekend-trips-from-accra', 'From the historic Cape Coast Castle to the lush Akosombo Dam, here are the best weekend getaways accessible from Accra.', '<h2>Ghana Has So Much to Offer</h2><p>Accra is a fantastic base for weekend exploration. Here are our top picks:</p><ul><li><strong>Cape Coast:</strong> 3 hours by road. Visit the UNESCO-listed Cape Coast Castle and pristine beaches.</li><li><strong>Akosombo:</strong> 2 hours. The Volta River boat cruise and Akosombo Dam are unmissable.</li><li><strong>Aburi Botanical Gardens:</strong> 45 minutes. A lush escape in the Akuapem Hills.</li><li><strong>Boti Falls:</strong> 2 hours. A stunning twin waterfall hidden in Eastern Ghana.</li></ul><p>Book a FlexyRide for your next adventure and explore Ghana in comfort.</p>', '', 'Travel & Lifestyle', true, '2026-03-10 17:56:47.814215-07', '2026-04-24 17:56:47.847055-07', '2026-04-24 17:56:47.847077-07', 'https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?q=80&w=800', 'travel');
INSERT INTO public.website_blogpost (id, title, slug, excerpt, content, cover_image, author_name, is_published, published_at, created_at, updated_at, cover_image_url, category) VALUES (9, 'FlexyRide Partners with Hotels for Airport Transfers', 'flexyride-partners-with-hotels-for-airport-transfe', 'We are proud to announce our new hotel partnership programme bringing seamless airport transfers to visitors across Ghana.', '<h2>A Seamless Arrival in Ghana</h2><p>FlexyRide has partnered with leading hotels across Accra and Kumasi to provide guests with seamless, pre-booked airport transfers at guaranteed rates.</p><p>Hotel partners can now offer their guests FlexyRide vouchers at check-in, redeemable for rides anywhere in the city.</p><h2>Partner With Us</h2><p>If you operate a hotel, lodge, or guest house and would like to join our partnership programme, contact us at <a href="mailto:partnerships@flexyridegh.com">partnerships@flexyridegh.com</a>.</p>', '', 'Partnerships Team', true, '2026-02-23 16:57:17.928621-08', '2026-04-24 17:57:17.941004-07', '2026-04-24 17:57:17.941015-07', 'https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?q=80&w=800', 'company');


