INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (1, 'How do I book a ride?', 'Open the FlexyRide Passenger app, enter your destination, select your preferred vehicle type, and tap Book. A nearby driver will be matched to you within seconds.', 'riders', 1, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (2, 'Can I schedule a ride in advance?', 'Yes! Tap the clock icon on the booking screen to schedule a ride up to 7 days in advance. You will receive a confirmation and a reminder 30 minutes before pickup.', 'riders', 2, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (3, 'What if my driver cancels?', 'If a driver cancels, the app will immediately re-match you with the next available driver. There is no additional charge for driver-initiated cancellations.', 'riders', 3, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (4, 'How do I share my trip with someone?', 'During a live trip, tap the Share button on the tracking screen and send the link to anyone. They will see your driver''s location and your estimated arrival time in real-time.', 'riders', 4, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (5, 'What is the cancellation policy for riders?', 'You can cancel for free within 2 minutes of booking. After 2 minutes, a small cancellation fee may apply if the driver is already on their way to you.', 'riders', 5, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (6, 'How do I sign up to drive with FlexyRide?', 'Download the FlexyRide Driver app, tap Sign Up, and complete the registration. You will need a valid Ghana driving licence, a roadworthy vehicle, and pass our background check.', 'drivers', 1, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (7, 'How quickly can I start earning?', 'Once your documents are verified and approved (typically 1–3 business days), you can start accepting rides immediately.', 'drivers', 2, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (8, 'When and how do I get paid?', 'Drivers receive daily payouts to their Mobile Money account. Earnings from trips completed by midnight are typically deposited the following morning.', 'drivers', 3, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (9, 'What percentage does FlexyRide take?', 'FlexyRide charges a 15% platform fee. You keep 85% of every fare — one of the best driver splits in Ghana.', 'drivers', 4, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (10, 'Can I drive my own vehicle?', 'Yes. You must use your own vehicle, which must pass our inspection for roadworthiness and cleanliness standards. Vehicle requirements vary by ride category.', 'drivers', 5, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (11, 'What payment methods are accepted?', 'We accept Mobile Money (MTN MoMo, Vodafone Cash, AirtelTigo Money), debit/credit cards, and FlexyRide Wallet balance.', 'payments', 1, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (12, 'Can I pay with cash?', 'Cash payments are currently not supported. All rides must be paid digitally through the app to ensure secure, transparent transactions.', 'payments', 2, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (13, 'How do I add money to my FlexyRide Wallet?', 'Go to Wallet in the app, tap Top Up, enter an amount, and select your Mobile Money number or card. Funds are added instantly.', 'payments', 3, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (14, 'What happens if I am overcharged?', 'Every fare is calculated by the app based on distance and time — drivers cannot change the price. If you believe there is an error, contact support within 24 hours with your trip ID.', 'payments', 4, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (15, 'How are drivers vetted?', 'Every driver undergoes a Ghana Police Service criminal background check, driving licence verification, and a vehicle roadworthiness inspection before being approved.', 'safety', 1, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (16, 'What should I do in an emergency during a ride?', 'Tap the SOS button (shield icon) on the live trip screen. This will immediately alert our 24/7 Incident Response Team and share your GPS location with them.', 'safety', 2, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (17, 'Can I verify my driver before getting in?', 'Yes. Before entering any vehicle, check that the car plate, driver photo, and name in the app match the vehicle and driver in front of you.', 'safety', 3, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (18, 'Which cities does FlexyRide operate in?', 'FlexyRide currently operates in Accra, Kumasi, Tamale, Takoradi, Cape Coast, and Sunyani, with more cities being added throughout 2025.', 'general', 1, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (19, 'How do I contact customer support?', 'You can reach our support team 24/7 via the in-app chat, email at support@flexyridegh.com, or through our Contact Us page on this website.', 'general', 2, true);
INSERT INTO public.website_faqitem (id, question, answer, category, "order", is_active) VALUES (20, 'Is there a FlexyRide for iOS?', 'The Android app is available now on Google Play. Our iOS app is currently in final testing and will be available on the App Store very soon.', 'general', 3, true);


