INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (7, 'Finance & Compliance Intern', 'finance', 'Accra, Ghana', 'internship', 'Support our finance team with reconciliations, driver payout reports, and compliance documentation. A great opportunity to gain hands-on fintech experience.', 'Pursuing or completed a degree in Finance, Accounting, or Economics. Proficient in Excel. Detail-oriented with strong numerical skills.', '', true, '2026-04-24 17:57:18.018092-07', '', '', 'finance-compliance-intern', '', '');
INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (6, 'UI/UX Designer', 'design', 'Accra, Ghana (Remote-Friendly)', 'full_time', 'Design beautiful, intuitive experiences for our Passenger app, Driver app, and website. You will run user research, create wireframes, and collaborate with engineering to bring designs to life.', '3+ years UI/UX design experience. Expert in Figma. Portfolio demonstrating strong visual design and user-centered thinking. Mobile app design experience is required.', '', true, '2026-04-24 17:57:18.015294-07', '', '', 'uiux-designer', '', '');
INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (5, 'Customer Support Lead', 'support', 'Accra, Ghana', 'full_time', 'Build and manage our customer support team to deliver world-class service to riders and drivers 24/7. You will define support processes, SLAs, and quality standards.', '3+ years in customer support leadership. Experience with support tooling (Freshdesk, Zendesk, or similar). Empathetic communicator with strong analytical skills.', '', true, '2026-04-24 17:57:18.012059-07', '', '', 'customer-support-lead', '', '');
INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (4, 'Growth Marketing Manager', 'marketing', 'Accra, Ghana', 'full_time', 'Own rider and driver acquisition campaigns across digital and traditional channels. Drive down CAC while increasing LTV through creative, data-driven campaigns.', '4+ years growth or performance marketing experience. Proven track record with Meta Ads and Google Ads. Experience in a two-sided marketplace is strongly preferred.', '', true, '2026-04-24 17:57:18.009211-07', '', '', 'growth-marketing-manager', '', '');
INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (3, 'City Operations Manager – Kumasi', 'operations', 'Kumasi, Ghana', 'full_time', 'Lead all on-the-ground operations in Kumasi. You will be responsible for driver acquisition, retention, quality assurance, and local partnerships.', '3+ years in operations or logistics management. Strong network in the Kumasi business community. Excellent communication and problem-solving skills.', '', true, '2026-04-24 17:57:18.005987-07', '', '', 'city-operations-manager-kumasi', '', '');
INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (2, 'Flutter Mobile Engineer', 'engineering', 'Accra, Ghana (Hybrid)', 'full_time', 'Build and maintain our Passenger and Driver apps used by hundreds of thousands of Ghanaians daily. You will work closely with our design and backend teams to ship impactful features.', '3+ years Flutter/Dart experience. Solid understanding of state management (BLoC preferred). Experience with Google Maps SDK and real-time location features.', '', true, '2026-04-24 17:57:18.00316-07', '', '', 'flutter-mobile-engineer', '', '');
INSERT INTO public.website_jobopening (id, title, department, location, job_type, description, requirements, apply_url, is_active, created_at, benefits, responsibilities, slug, about_company, how_to_apply) VALUES (1, 'Senior Backend Engineer (Python/Django)', 'engineering', 'Accra, Ghana (Hybrid)', 'full_time', 'We are looking for a Senior Backend Engineer to help scale our ride-hailing platform to millions of users. You will own core services including ride matching, pricing, and payments.', '5+ years Python experience. Strong knowledge of Django REST Framework. Experience with PostgreSQL, Redis, and Celery. Familiarity with real-time systems (WebSockets, channels) is a plus.', '', true, '2026-04-24 17:57:18.000069-07', '', '', 'senior-backend-engineer-pythondjango', '', '');


