INSERT INTO public.website_servicecategory (id, name, description, image, image_url, "order", is_active) VALUES (1, 'Flexy CC', 'WRearferfwererfed', 'services/photo_2026-05-05_13-22-44.jpg', NULL, 0, true);
INSERT INTO public.website_servicecategory (id, name, description, image, image_url, "order", is_active) VALUES (2, 'Flexy Go', 'Your go-to option for quick, budget-friendly trips around the city. Whether it is your daily commute, a quick errand, or a trip to the market — Flexy Go gets you there fast without breaking the bank. Compact, reliable, and always just a tap away.', '', NULL, 1, true);
INSERT INTO public.website_servicecategory (id, name, description, image, image_url, "order", is_active) VALUES (3, 'Flexy Comfort', 'Upgrade your journey with spacious sedans, climate-controlled cabins, and top-rated drivers. Flexy Comfort is perfect for business meetings, airport transfers, or any occasion where first impressions matter. Premium comfort at an accessible price.', '', NULL, 2, true);
INSERT INTO public.website_servicecategory (id, name, description, image, image_url, "order", is_active) VALUES (4, 'Flexy XL', 'Travelling with family, friends, or extra luggage? Flexy XL offers spacious SUVs and minivans that seat up to 6 passengers comfortably. Ideal for group outings, weekend getaways, and airport runs with heavy bags.', '', NULL, 3, true);
INSERT INTO public.website_servicecategory (id, name, description, image, image_url, "order", is_active) VALUES (5, 'Flexy Exec', 'Arrive like a VIP. Flexy Exec pairs you with luxury vehicles and professionally trained chauffeurs for a first-class travel experience. From corporate events to special celebrations, this is the premium tier for those who demand the very best.', '', NULL, 4, true);
INSERT INTO public.website_servicecategory (id, name, description, image, image_url, "order", is_active) VALUES (6, 'Flexy Pragya', 'Ghana''s favourite way to navigate busy streets. Flexy Pragya connects you with licensed motorbike riders for the fastest point-to-point trips in the city. Perfect for short distances, tight schedules, and peak-hour traffic.', '', NULL, 5, true);


