INSERT INTO public.website_testimonial (id, name, role, quote, photo_url, rating, created_at) VALUES (1, 'Kwame Mensah', 'Daily Rider', 'FlexyRide has completely changed how I commute to Work. The drivers are polite, and the fares are the most competitive in Accra.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200', 5, '2026-04-21 18:07:21.604581-07');
INSERT INTO public.website_testimonial (id, name, role, quote, photo_url, rating, created_at) VALUES (2, 'Abena Osei', 'Business Owner', 'The Flexy Delivery service is a lifesaver for my boutique. Packages always arrive on time, and my customers love the real-time tracking.', 'https://images.unsplash.com/photo-1531123897727-8f129e16fd3c?q=80&w=200', 5, '2026-04-21 18:07:21.607449-07');
INSERT INTO public.website_testimonial (id, name, role, quote, photo_url, rating, created_at) VALUES (3, 'Samuel Boateng', 'Flexy Driver', 'Driving with FlexyRide gives me the flexibility I need. The instant payouts help me manage my finances much better than other apps.', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200', 5, '2026-04-21 18:07:21.609816-07');
INSERT INTO public.website_testimonial (id, name, role, quote, photo_url, rating, created_at) VALUES (4, 'Ama Darkwa', 'University Student', 'As a student on a budget, the affordable fares and the student promo codes make FlexyRide my go-to for getting around Kumasi safely late at night.', 'https://images.unsplash.com/photo-1529626455594-4ff0802cfb7e?q=80&w=200', 5, '2026-04-24 17:56:05.357437-07');
INSERT INTO public.website_testimonial (id, name, role, quote, photo_url, rating, created_at) VALUES (5, 'Emmanuel Tetteh', 'Corporate Client', 'We moved our entire staff transport to FlexyRide Corporate. The invoicing is clean, the drivers are professional, and our account manager responds within minutes.', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200', 5, '2026-04-24 17:56:05.36208-07');


